/* * VirtualMouseDevice.cs - Abstract base for platform-specific virtual mouse devices */ using System; namespace H1161TouchStrip { public enum EventType : uint { EV_SYN = 0x00, EV_REL = 0x02, } public enum EventCode : uint { SYN_REPORT = 0, REL_WHEEL = 0x08, REL_WHEEL_HI_RES = 0x0B, REL_HWHEEL = 0x06, REL_HWHEEL_HI_RES = 0x0C, } public enum ERRNO : int { NONE = 0, } public abstract class VirtualMouseDevice : IDisposable { public bool CanWrite { get; protected set; } = false; public abstract int Initialize(); public virtual void EnableType(EventType type) { } public virtual void EnableCode(EventType type, EventCode code) { } public virtual void EnableTypeCodes(EventType type, params EventCode[] codes) { EnableType(type); foreach (var code in codes) EnableCode(type, code); } public virtual int Write(EventType type, EventCode code, int value) { if (!CanWrite) return int.MinValue; if (type == EventType.EV_REL) { if (code == EventCode.REL_WHEEL || code == EventCode.REL_WHEEL_HI_RES) return SendScrollImpl(value, horizontal: false); if (code == EventCode.REL_HWHEEL || code == EventCode.REL_HWHEEL_HI_RES) return SendScrollImpl(value, horizontal: true); } return 0; } public virtual bool Sync() => true; protected abstract int SendScrollImpl(int value, bool horizontal); private bool _disposed = false; public virtual void Dispose() { if (!_disposed) { CanWrite = false; _disposed = true; } } } }